const input = $input.first().json;

const html = input.body || input.data || input.html || '';

const sourceData = $('Set Learn Data').first().json;

function decodeHtmlEntities(text) {
  return text
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");
}

let pageTitle = '';
const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
if (titleMatch) {
  pageTitle = decodeHtmlEntities(titleMatch[1]).trim();
}

let cleaned = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
  .replace(/<svg[\s\S]*?<\/svg>/gi, ' ')
  .replace(/<iframe[\s\S]*?<\/iframe>/gi, ' ')
  .replace(/<\/(p|div|section|article|h1|h2|h3|h4|h5|h6|li|br)>/gi, '\n')
  .replace(/<[^>]+>/g, ' ');

cleaned = decodeHtmlEntities(cleaned)
  .replace(/\r/g, ' ')
  .replace(/\t/g, ' ')
  .replace(/\n\s*\n+/g, '\n')
  .replace(/[ ]{2,}/g, ' ')
  .replace(/\n+/g, '\n')
  .trim();

// Можно сразу ограничить длину,
// чтобы дальше не тащить огромные страницы.
const maxLength = 15000;
const content =
  cleaned.length > maxLength ? cleaned.slice(0, maxLength) : cleaned;

return [
  {
    json: {
      url: sourceData.url,
      chatId: sourceData.chatId,
      telegramUserId: sourceData.telegramUserId,
      pageTitle,
      content,
    },
  },
];

const input = $input.first().json;
const rawUrl = String(input.url || '').trim();

const urlRegex =
  /^(https?:\/\/)([\w-]+\.)+[\w-]+(\/[^\s]*)?$/i;

const isValidUrl = urlRegex.test(rawUrl);

return [
  {
    json: {
      ...input,
      rawUrl,
      normalizedUrl: rawUrl,
      isValidUrl,
      validationError: isValidUrl
        ? null
        : 'URL must start with http:// or https:// and contain a valid domain',
    },
  },
];

