const sourceData = $('Extract Page Content').first().json;
const aiOutput = $input.first().json;

const raw =
  aiOutput.text ||
  aiOutput.response ||
  aiOutput.content ||
  aiOutput.output ||
  '';

let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (error) {
  throw new Error(`Teacher returned invalid JSON: ${raw}`);
}

if (
  !parsed.title ||
  !parsed.difficulty ||
  !Array.isArray(parsed.keyPoints) ||
  !Array.isArray(parsed.mainConcepts)
) {
  throw new Error('Teacher response is missing required fields.');
}

if (parsed.keyPoints.length < 5 || parsed.keyPoints.length > 7) {
  throw new Error('Teacher must return between 5 and 7 key points.');
}

const difficulty = String(parsed.difficulty).toLowerCase();
if (!['beginner', 'intermediate', 'advanced'].includes(difficulty)) {
  throw new Error('Teacher returned an invalid difficulty value.');
}

return [
  {
    json: {
      ...sourceData,
      teacherResult: {
        title: String(parsed.title).trim(),
        difficulty,
        keyPoints: parsed.keyPoints.map((item) => String(item).trim()),
        mainConcepts: parsed.mainConcepts.map((item) =>
          String(item).trim()
        ),
      },
    },
  },
];

const input = $input.first().json;

const materialId = `LM-${Date.now()}-${input.telegramUserId}`;

return [
  {
    json: {
      ...input,
      materialId,
      summaryJson: {
        title: input.teacherResult.title,
        keyPoints: input.teacherResult.keyPoints,
        mainConcepts: input.teacherResult.mainConcepts,
