const sourceData = $('Prepare Examiner Input').first().json;
const aiOutput = $input.first().json;

const raw = aiOutput.output || '';

let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (error) {
  throw new Error(`Examiner returned invalid JSON: ${raw}`);
}

if (!Array.isArray(parsed.questions) || parsed.questions.length !== 5) {
  throw new Error('Examiner must return exactly 5 questions.');
}

const questions = parsed.questions.map((q, index) => {
  if (
    !q.id ||
    !q.question ||
    !q.options ||
    !q.correctAnswer ||
    !q.explanation
  ) {
    throw new Error(`Question ${index + 1} is missing required fields.`);
  }

  const optionKeys = ['A', 'B', 'C', 'D'];
  for (const key of optionKeys) {
    if (!q.options[key]) {
      throw new Error(`Question ${index + 1} is missing option ${key}.`);
    }
  }

  if (!optionKeys.includes(q.correctAnswer)) {
    throw new Error(
      `Question ${index + 1} has invalid correctAnswer value.`
    );
  }

  return {
    id: String(q.id),
    question: String(q.question).trim(),
    options: {
      A: String(q.options.A).trim(),
      B: String(q.options.B).trim(),
      C: String(q.options.C).trim(),
      D: String(q.options.D).trim(),
    },
    correctAnswer: String(q.correctAnswer).trim(),
    explanation: String(q.explanation).trim(),
    questionOrder: index + 1,
  };
});

return [
  {
    json: {
      ...sourceData,
      questions,
    },
  },
];

