}));

const items = $('Split Quiz Questions').all();

if (!items.length) {
  throw new Error('No quiz question items found in Split Quiz Questions.');
}

const first = items[0].json;

return [
  {
    json: {
      quizId: first.quizId,
      sessionId: first.sessionId,
      chatId: first.chatId,
      telegramUserId: first.telegramUserId,
    },
  },
];

const items = $input.all();
const source = $('Set Quiz Command Data').first().json;

return [
  {
    json: {
      chatId: source.chatId,
      telegramUserId: source.telegramUserId,
      materials: items.map((item) => item.json),
      materialsCount: items.length,
    },
  },
];

const input = $input.first().json;

const inlineKeyboard = input.materials.map((material) => [
  {
    text: `${material.title}`,
    callback_data: `quiz_select:${material.id}`,
  },
]);

return [
  {
    json: {
      ...input,
      inlineKeyboard,
    },
  },
];

