const input = $input.first().json;
const callbackData = String(input.callbackData || '');

const parts = callbackData.split(':');

if (parts.length !== 4 || parts[0] !== 'ans') {
  throw new Error(`Invalid answer callback format: ${callbackData}`);
}

const sessionId = parts[1];
const questionOrder = Number(parts[2])
const selectedAnswer = parts[3];

if (!Number.isInteger(questionOrder) || questionOrder < 1) {
  throw new Error(`Invalid question order in callback: ${callbackData}`);
}

return [
  {
    json: {
      chatId: input.chatId,
      telegramUserId: input.telegramUserId,
      messageId: input.messageId,
      callbackData,
      sessionId,
      questionOrder,
      selectedAnswer,
    },
  },
];

const session = $input.first().json;
const callback = $('Parse Answer Callback').first().json;

if (!session.id) {
  throw new Error('Quiz session not found.');
}

const normalizedStatus = String(session.status || '')
  .replace(/^'+|'+$/g, '')
  .trim();

const currentQuestionOrder = Number(session.current_question_order);
const callbackQuestionOrder = Number(callback.questionOrder);

const sessionActive = normalizedStatus === 'in_progress';
const isCurrentQuestion = callbackQuestionOrder === currentQuestionOrder;

return [
  {
    json: {
      ...callback,
      sessionFound: true,
      sessionActive,
      isCurrentQuestion,
      quizId: session.quiz_id,
      currentQuestionOrder,
      status: normalizedStatus,
    },
  },
];

const question = $input.first().json;
const context = $('Prepare Current Session Context').first().json;

const selectedAnswer = String(context.selectedAnswer).trim();
const correctAnswer = String(question.correct_answer).trim();
const isCorrect = selectedAnswer === correctAnswer;

const options =
  typeof question.options_json === 'string'
    ? JSON.parse(question.options_json)
    : question.options_json;

return [
  {
    json: {
      chatId: context.chatId,
      telegramUserId: context.telegramUserId,
      sessionId: context.sessionId,
      quizId: context.quizId,
      currentQuestionOrder: context.currentQuestionOrder,
      questionId: question.id,
      selectedAnswer,
      correctAnswer,
      isCorrect,
      explanation: question.explanation,
      questionText: question.question_text,
      options,
