const titleRow = $input.first().json;
const summary = $('Summarize Quiz Results').first().json;

const lines = [
  `Quiz completed!`,
  '',
  `Topic: ${titleRow.title}`,
  `Score: ${summary.correctCount}/${summary.totalQuestions} (${summary.scorePercent}%)`,
  '',
  `Feedback:`,
];

for (const result of summary.results) {
  const status = result.isCorrect ? 'Correct' : 'Incorrect';

  lines.push('');
  lines.push(`Q${result.questionOrder}: ${status}`);
  lines.push(
    `Your answer: ${result.selectedAnswer}. ${
      result.options[result.selectedAnswer] || ''
    }`
  );
  lines.push(
    `Correct answer: ${result.correctAnswer}. ${
      result.options[result.correctAnswer] || ''
    }`
  );

  if (!result.isCorrect) {
    lines.push(`Explanation: ${result.explanation}`);
  }
}

const resultsMessage = lines.join('\n');

return [
  {
    json: {
      chatId: summary.chatId,
      resultsMessage,
    },
  },
];

const items = $input.all();
const context = $('Decide Next Step').first().json;

if (!items.length) {
  throw new Error('No quiz answers found for this session.');
}

const results = items.map((item) => {
  const row = item.json;
  const options =
    typeof row.options_json === 'string'
      ? JSON.parse(row.options_json)
      : row.options_json;

  return {
    questionId: row.question_id,
    questionOrder: row.question_order,
    questionText: row.question_text,
    options,
    selectedAnswer: row.selected_answer,
    correctAnswer: row.correct_answer,
    isCorrect: row.is_correct,
    explanation: row.explanation,
  };
});

const correctCount = results.filter((r) => r.isCorrect).length;
const totalQuestions = results.length;
const scorePercent = Math.round((correctCount / totalQuestions) * 100);

return [
  {
    json: {
      chatId: context.chatId,
      telegramUserId: context.telegramUserId,
      sessionId: context.sessionId,
      quizId: context.quizId,
      correctCount,
      totalQuestions,
      scorePercent,
      results,
    },
  },
];

const items = $input.all();
const source = $('Evaluate Answer').first().json;

const first = items[0]?.json || {};
const alreadyAnswered = !!first.id;

return [
  {
    json: {
      ...source,
      alreadyAnswered,
    },
  },
];
